import React, { useState, useRef, useEffect, useLayoutEffect, useCallback } from "react";
import {
  Upload, Plus, Trash2, Eye, EyeOff, Lock, Unlock, ChevronUp, ChevronDown,
  Download, Copy, RotateCcw, Hand, Pointer
} from "lucide-react";

/* GUI FORGE — loaded with real Greener Pastures art (frame + dragon crest) */

const T = {
  page: "#0b0710", chrome: "#14101c", chrome2: "#1b1526", line: "#2c2440",
  accent: "#a855f7", accentHi: "#c084fc", text: "#e9e3f5", muted: "#9a8fb0", good: "#34d399",
};

const CHAR_DATA = "data:image/png;base64,";
const CHANSEY_DATA = "data:image/png;base64,";
const LOGO_DATA = "data:image/png;base64,";
const BG_DATA = "data:image/jpeg;base64,";

const svgUrl = (s) => "data:image/svg+xml," + encodeURIComponent(s);
const button_svg = (label) => `
<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 120 30'>
  <defs><linearGradient id='b' x1='0' y1='0' x2='0' y2='1'>
    <stop offset='0' stop-color='#a855f7'/><stop offset='1' stop-color='#5b21b6'/></linearGradient></defs>
  <rect x='1' y='1' width='118' height='28' rx='7' fill='url(#b)' stroke='#e9d5ff' stroke-width='1.5'/>
  <rect x='4' y='4' width='112' height='10' rx='5' fill='#ffffff' opacity='0.18'/>
  <text x='60' y='21' text-anchor='middle' font-family='monospace' font-size='13'
        font-weight='700' fill='#fff' letter-spacing='2'>${label}</text>
</svg>`;

const title_svg = (label) => `
<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 152 24'>
  <defs><linearGradient id='t' x1='0' y1='0' x2='0' y2='1'>
    <stop offset='0' stop-color='#7c3aed'/><stop offset='1' stop-color='#3b0d6b'/></linearGradient></defs>
  <path d='M8 2 H144 L150 12 L144 22 H8 L2 12 Z' fill='url(#t)' stroke='#e9d5ff' stroke-width='1.5'/>
  <text x='76' y='16' text-anchor='middle' font-family='monospace' font-size='11'
        font-weight='700' fill='#fff' letter-spacing='1'>${label}</text>
</svg>`;

const chapter_svg = (label) => `
<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 150 20'>
  <defs><linearGradient id='c' x1='0' y1='0' x2='0' y2='1'>
    <stop offset='0' stop-color='#9333ea'/><stop offset='1' stop-color='#581c87'/></linearGradient></defs>
  <rect x='1' y='1' width='148' height='18' rx='5' fill='url(#c)' stroke='#c084fc' stroke-width='1'/>
  <rect x='4' y='3' width='142' height='6' rx='3' fill='#ffffff' opacity='0.12'/>
  <rect x='9' y='7' width='6' height='6' transform='rotate(45 12 10)' fill='#e9d5ff'/>
  <text x='80' y='14' text-anchor='middle' font-family='monospace' font-size='10'
        font-weight='700' fill='#fff' letter-spacing='1'>${label}</text>
</svg>`;

const makeStarter = () => [
  { id: "BG", name: "background", src: BG_DATA,      x: 0,   y: 0,  w: 280, h: 153, z: 0, visible: true, locked: false, isButton: false, buttonId: "" },
  { id: "L6", name: "charmander", src: CHAR_DATA,    x: 4,   y: 85, w: 86,  h: 64,  z: 2, visible: true, locked: false, isButton: false, buttonId: "" },
  { id: "L7", name: "chansey",    src: CHANSEY_DATA, x: 198, y: 84, w: 78,  h: 64,  z: 2, visible: true, locked: false, isButton: false, buttonId: "" },
  { id: "L9", name: "logo",       src: LOGO_DATA,    x: 65,  y: 2,  w: 150, h: 75,  z: 3, visible: true, locked: false, isButton: false, buttonId: "" },
];

let _idc = 100;
const nextId = () => "L" + (++_idc);

export default function GUIForge() {
  const [panel, setPanel] = useState({ w: 280, h: 153 });
  const [guiScale, setGuiScale] = useState("auto");
  const [pixelated, setPixelated] = useState(false);
  const [mode, setMode] = useState("edit");
  const [layers, setLayers] = useState(makeStarter);
  const [selectedId, setSelectedId] = useState("L9");
  const [pressed, setPressed] = useState(null);
  const [log, setLog] = useState([]);
  const [stageSize, setStageSize] = useState({ w: 760, h: 460 });

  const stageRef = useRef(null);
  const dragRef = useRef(null);
  const addInputRef = useRef(null);
  const replaceInputRef = useRef(null);
  const replaceTargetRef = useRef(null);

  useLayoutEffect(() => {
    const el = stageRef.current; if (!el) return;
    const ro = new ResizeObserver(() => setStageSize({ w: el.clientWidth, h: el.clientHeight }));
    ro.observe(el); setStageSize({ w: el.clientWidth, h: el.clientHeight });
    return () => ro.disconnect();
  }, []);

  const autoScale = (() => {
    const maxW = stageSize.w * 0.86, maxH = stageSize.h * 0.86;
    let s = 1;
    for (let i = 4; i >= 1; i--) if (panel.w * i <= maxW && panel.h * i <= maxH) { s = i; break; }
    return s;
  })();
  const scale = guiScale === "auto" ? autoScale : guiScale;
  const panelPxW = panel.w * scale, panelPxH = panel.h * scale;

  const updateLayer = useCallback((id, patch) =>
    setLayers((ls) => ls.map((l) => (l.id === id ? { ...l, ...patch } : l))), []);

  const moveZ = (id, dir) => setLayers((ls) => {
    const arr = [...ls].sort((a, b) => a.z - b.z);
    const i = arr.findIndex((l) => l.id === id), j = i + dir;
    if (i < 0 || j < 0 || j >= arr.length) return ls;
    const zi = arr[i].z, zj = arr[j].z;
    return ls.map((l) => l.id === arr[i].id ? { ...l, z: zj } : l.id === arr[j].id ? { ...l, z: zi } : l);
  });

  const delLayer = (id) => { setLayers((ls) => ls.filter((l) => l.id !== id)); setSelectedId((s) => (s === id ? null : s)); };

  const addImageFiles = (files) => Array.from(files).forEach((file) => {
    const reader = new FileReader();
    reader.onload = () => {
      const src = reader.result; const img = new Image();
      img.onload = () => {
        const fitW = Math.min(panel.w * 0.6, img.naturalWidth);
        const ratio = img.naturalHeight / img.naturalWidth;
        const w = Math.round(fitW), h = Math.round(fitW * ratio), id = nextId();
        const maxZ = Math.max(0, ...layers.map((l) => l.z));
        setLayers((ls) => [...ls, { id, name: file.name.replace(/\.[^.]+$/, ""), src,
          x: Math.round((panel.w - w) / 2), y: Math.round((panel.h - h) / 2),
          w, h, z: maxZ + 1, visible: true, locked: false, isButton: false, buttonId: "" }]);
        setSelectedId(id);
      };
      img.src = src;
    };
    reader.readAsDataURL(file);
  });

  const replaceTexture = (file) => {
    const id = replaceTargetRef.current; if (!id) return;
    const reader = new FileReader();
    reader.onload = () => updateLayer(id, { src: reader.result });
    reader.readAsDataURL(file);
  };

  const startDrag = (e, layer, kind) => {
    if (mode !== "edit" || layer.locked) return;
    e.stopPropagation(); setSelectedId(layer.id);
    dragRef.current = { id: layer.id, kind, sx: e.clientX, sy: e.clientY,
      ox: layer.x, oy: layer.y, ow: layer.w, oh: layer.h, aspect: layer.h / layer.w, scale };
    window.addEventListener("pointermove", onMove);
    window.addEventListener("pointerup", onUp);
  };
  const onMove = (e) => {
    const d = dragRef.current; if (!d) return;
    const dx = Math.round((e.clientX - d.sx) / d.scale), dy = Math.round((e.clientY - d.sy) / d.scale);
    if (d.kind === "move") updateLayer(d.id, { x: d.ox + dx, y: d.oy + dy });
    else { const w = Math.max(8, d.ow + dx); updateLayer(d.id, { w, h: Math.max(8, Math.round(w * d.aspect)) }); }
  };
  const onUp = () => { dragRef.current = null;
    window.removeEventListener("pointermove", onMove); window.removeEventListener("pointerup", onUp); };

  const fireButton = (layer) => {
    if (mode !== "preview" || !layer.isButton) return;
    setPressed(layer.id);
    setTimeout(() => setPressed((p) => (p === layer.id ? null : p)), 120);
    setLog((l) => [{ t: Date.now(), id: layer.buttonId || layer.name }, ...l].slice(0, 7));
  };

  const layoutJSON = () => JSON.stringify({
    note: "Greener Pastures GUI layout. Coords are NATIVE Minecraft GUI px at 1x. Negative y = bleeds above panel.",
    panel, guiScale, pixelated,
    layers: [...layers].sort((a, b) => a.z - b.z).map((l) => ({
      name: l.name, x: l.x, y: l.y, w: l.w, h: l.h, z: l.z, isButton: l.isButton, buttonId: l.buttonId, visible: l.visible })),
  }, null, 2);
  const copyJSON = () => navigator.clipboard?.writeText(layoutJSON());
  const downloadJSON = () => {
    const blob = new Blob([layoutJSON()], { type: "application/json" });
    const a = document.createElement("a"); a.href = URL.createObjectURL(blob);
    a.download = "gui-layout.json"; a.click(); URL.revokeObjectURL(a.href);
  };

  const selected = layers.find((l) => l.id === selectedId) || null;
  const ordered = [...layers].sort((a, b) => b.z - a.z);

  const Btn = ({ active, onClick, children, title, danger }) => (
    <button title={title} onClick={onClick}
      style={{ background: active ? T.accent : T.chrome2, border: `1px solid ${active ? T.accentHi : T.line}`,
               color: danger ? "#fda4af" : active ? "#fff" : T.text }}
      className="px-2 py-1 rounded text-xs font-mono flex items-center gap-1 transition-colors">{children}</button>
  );
  const numField = (label, val, onCh) => (
    <label className="flex items-center justify-between gap-2 text-xs font-mono" style={{ color: T.muted }}>
      <span>{label}</span>
      <input type="number" value={val} onChange={(e) => onCh(parseInt(e.target.value || "0", 10))}
        style={{ background: T.page, border: `1px solid ${T.line}`, color: T.text, width: 64 }}
        className="px-1.5 py-1 rounded text-right" />
    </label>
  );

  return (
    <div style={{ background: T.page, color: T.text, minHeight: 640 }} className="w-full rounded-lg overflow-hidden font-sans flex flex-col">
      <div style={{ background: T.chrome, borderBottom: `1px solid ${T.line}` }} className="flex items-center justify-between px-4 py-2.5 flex-wrap gap-2">
        <div className="flex items-center gap-2">
          <div style={{ width: 10, height: 10, background: T.accent, boxShadow: `0 0 10px ${T.accent}` }} className="rounded-sm" />
          <span className="font-mono text-sm font-bold tracking-widest" style={{ color: T.accentHi }}>GUI FORGE</span>
          <span className="text-xs font-mono" style={{ color: T.muted }}>· greener pastures</span>
        </div>
        <div className="flex items-center gap-2 flex-wrap">
          <div className="flex gap-1">
            <Btn active={mode === "edit"} onClick={() => setMode("edit")} title="Move & arrange layers"><Hand size={13} /> Edit</Btn>
            <Btn active={mode === "preview"} onClick={() => setMode("preview")} title="Buttons go live"><Pointer size={13} /> Preview</Btn>
          </div>
          <div style={{ width: 1, height: 20, background: T.line }} />
          <Btn active={!pixelated} onClick={() => setPixelated(false)} title="Smooth (Cobblemon)">Smooth</Btn>
          <Btn active={pixelated} onClick={() => setPixelated(true)} title="Nearest-neighbor (vanilla)">Pixel</Btn>
        </div>
      </div>

      <div className="flex flex-1 flex-col lg:flex-row">
        <div className="flex-1 flex flex-col" style={{ minWidth: 0 }}>
          <div ref={stageRef} onPointerDown={() => mode === "edit" && setSelectedId(null)}
            style={{ background: "radial-gradient(circle at 50% 38%, #1d1430 0%, #0b0710 70%)", minHeight: 460, position: "relative", overflow: "hidden" }}
            className="flex-1 flex items-center justify-center select-none">
            <div style={{ position: "absolute", inset: 0, pointerEvents: "none", opacity: 0.10,
              backgroundImage: `linear-gradient(${T.accent} 1px, transparent 1px), linear-gradient(90deg, ${T.accent} 1px, transparent 1px)`,
              backgroundSize: "32px 32px" }} />
            <div style={{ position: "relative", width: panelPxW, height: panelPxH, outline: mode === "edit" ? `1px dashed ${T.line}` : "none" }}>
              {[...layers].sort((a, b) => a.z - b.z).map((l) => {
                if (!l.visible) return null;
                const isSel = l.id === selectedId && mode === "edit";
                const isPressed = pressed === l.id;
                return (
                  <div key={l.id}
                    onPointerDown={(e) => mode === "edit" ? startDrag(e, l, "move") : null}
                    onClick={() => fireButton(l)}
                    style={{ position: "absolute", left: l.x * scale, top: l.y * scale, width: l.w * scale, height: l.h * scale, zIndex: l.z,
                      cursor: mode === "preview" ? (l.isButton ? "pointer" : "default") : (l.locked ? "default" : "move"),
                      transform: isPressed ? "translateY(1px)" : "none", filter: isPressed ? "brightness(1.25)" : "none" }}>
                    <img src={l.src} alt={l.name} draggable={false}
                      style={{ width: "100%", height: "100%", display: "block", imageRendering: pixelated ? "pixelated" : "auto", pointerEvents: "none" }} />
                    {mode === "edit" && l.isButton && (
                      <div style={{ position: "absolute", inset: 0, outline: `1.5px dotted ${T.accentHi}`, pointerEvents: "none" }}>
                        <span style={{ position: "absolute", top: -16, left: 0, background: T.accent, color: "#fff", fontSize: 9, padding: "1px 4px", borderRadius: 3 }} className="font-mono">BTN</span>
                      </div>
                    )}
                    {isSel && (
                      <>
                        <div style={{ position: "absolute", inset: -2, outline: "2px dashed #fff", pointerEvents: "none" }} />
                        <span style={{ position: "absolute", top: -16, right: 0, background: "#fff", color: "#000", fontSize: 9, padding: "1px 4px", borderRadius: 3 }} className="font-mono">{l.name}</span>
                        {!l.locked && (
                          <div onPointerDown={(e) => startDrag(e, l, "resize")}
                            style={{ position: "absolute", right: -6, bottom: -6, width: 12, height: 12, background: "#fff", border: `2px solid ${T.accent}`, borderRadius: 2, cursor: "nwse-resize" }} />
                        )}
                      </>
                    )}
                  </div>
                );
              })}
            </div>
            <div style={{ position: "absolute", left: 12, bottom: 10, color: T.muted }} className="font-mono text-xs space-y-0.5">
              <div>scale: <span style={{ color: T.accentHi }}>{guiScale === "auto" ? `Auto (${scale}×)` : `${scale}×`}</span></div>
              <div>native: {panel.w}×{panel.h}px · drawn: {panelPxW}×{panelPxH}px</div>
            </div>
            {mode === "preview" && (
              <div style={{ position: "absolute", right: 12, top: 12, width: 150 }} className="font-mono text-xs">
                <div style={{ color: T.muted }} className="mb-1">click log</div>
                {log.length === 0 && <div style={{ color: T.line }}>— tap a button —</div>}
                {log.map((e) => (<div key={e.t} style={{ color: T.good }}>▸ {e.id}</div>))}
              </div>
            )}
          </div>
          <div style={{ background: T.chrome, borderTop: `1px solid ${T.line}` }} className="flex items-center gap-2 px-4 py-2 flex-wrap">
            <span className="text-xs font-mono" style={{ color: T.muted }}>GUI Scale</span>
            <Btn active={guiScale === "auto"} onClick={() => setGuiScale("auto")}>Auto</Btn>
            {[1, 2, 3, 4].map((s) => (<Btn key={s} active={guiScale === s} onClick={() => setGuiScale(s)}>{s}×</Btn>))}
            <span className="text-xs font-mono ml-2" style={{ color: T.line }}>↑ exactly how the player's GUI Scale setting works in-game</span>
          </div>
        </div>

        <div style={{ background: T.chrome, borderLeft: `1px solid ${T.line}`, width: 320 }} className="flex-shrink-0 flex flex-col">
          <div style={{ borderBottom: `1px solid ${T.line}` }} className="p-3 space-y-2">
            <div className="text-xs font-mono uppercase tracking-wider" style={{ color: T.accentHi }}>Panel · native px</div>
            {numField("width", panel.w, (v) => setPanel((p) => ({ ...p, w: Math.max(16, v) })))}
            {numField("height", panel.h, (v) => setPanel((p) => ({ ...p, h: Math.max(16, v) })))}
          </div>
          <div className="flex-1 overflow-auto">
            <div className="flex items-center justify-between px-3 pt-3 pb-1">
              <span className="text-xs font-mono uppercase tracking-wider" style={{ color: T.accentHi }}>Layers</span>
              <button onClick={() => addInputRef.current?.click()} style={{ background: T.accent, color: "#fff" }} className="px-2 py-1 rounded text-xs font-mono flex items-center gap-1"><Plus size={12} /> Add PNG</button>
              <input ref={addInputRef} type="file" accept="image/*" multiple hidden onChange={(e) => { addImageFiles(e.target.files); e.target.value = ""; }} />
            </div>
            <div className="px-2 pb-2 space-y-1">
              {ordered.map((l) => {
                const sel = l.id === selectedId;
                return (
                  <div key={l.id} onClick={() => setSelectedId(l.id)}
                    style={{ background: sel ? T.chrome2 : "transparent", border: `1px solid ${sel ? T.accent : "transparent"}` }} className="rounded p-1.5 cursor-pointer">
                    <div className="flex items-center gap-1.5">
                      <img src={l.src} alt="" style={{ width: 22, height: 22, objectFit: "contain", background: "#0007", borderRadius: 3, imageRendering: pixelated ? "pixelated" : "auto" }} />
                      <span className="text-xs font-mono flex-1 truncate" style={{ color: l.visible ? T.text : T.muted }}>{l.name}</span>
                      {l.isButton && <span style={{ color: T.accentHi }} className="text-xs font-mono">btn</span>}
                    </div>
                    <div className="flex items-center gap-1 mt-1">
                      <Btn onClick={() => updateLayer(l.id, { visible: !l.visible })} title="Show/hide">{l.visible ? <Eye size={12} /> : <EyeOff size={12} />}</Btn>
                      <Btn onClick={() => updateLayer(l.id, { locked: !l.locked })} title="Lock">{l.locked ? <Lock size={12} /> : <Unlock size={12} />}</Btn>
                      <Btn onClick={() => moveZ(l.id, +1)} title="Bring forward"><ChevronUp size={12} /></Btn>
                      <Btn onClick={() => moveZ(l.id, -1)} title="Send back"><ChevronDown size={12} /></Btn>
                      <Btn onClick={() => { replaceTargetRef.current = l.id; replaceInputRef.current?.click(); }} title="Swap texture"><Upload size={12} /></Btn>
                      <Btn onClick={() => delLayer(l.id)} title="Delete" danger><Trash2 size={12} /></Btn>
                    </div>
                  </div>
                );
              })}
            </div>
            <input ref={replaceInputRef} type="file" accept="image/*" hidden onChange={(e) => { replaceTexture(e.target.files[0]); e.target.value = ""; }} />
          </div>
          {selected && (
            <div style={{ borderTop: `1px solid ${T.line}`, background: T.chrome2 }} className="p-3 space-y-2">
              <div className="text-xs font-mono uppercase tracking-wider" style={{ color: T.accentHi }}>{selected.name}</div>
              <input value={selected.name} onChange={(e) => updateLayer(selected.id, { name: e.target.value })}
                style={{ background: T.page, border: `1px solid ${T.line}`, color: T.text }} className="w-full px-2 py-1 rounded text-xs font-mono" />
              <div className="grid grid-cols-2 gap-2">
                {numField("x", selected.x, (v) => updateLayer(selected.id, { x: v }))}
                {numField("y", selected.y, (v) => updateLayer(selected.id, { y: v }))}
                {numField("w", selected.w, (v) => updateLayer(selected.id, { w: Math.max(8, v) }))}
                {numField("h", selected.h, (v) => updateLayer(selected.id, { h: Math.max(8, v) }))}
              </div>
              <label className="flex items-center gap-2 text-xs font-mono" style={{ color: T.text }}>
                <input type="checkbox" checked={selected.isButton} onChange={(e) => updateLayer(selected.id, { isButton: e.target.checked })} />
                make this a button (hotspot)
              </label>
              {selected.isButton && (
                <label className="flex items-center justify-between gap-2 text-xs font-mono" style={{ color: T.muted }}>
                  <span>action id</span>
                  <input value={selected.buttonId} placeholder="e.g. open_breeder" onChange={(e) => updateLayer(selected.id, { buttonId: e.target.value })}
                    style={{ background: T.page, border: `1px solid ${T.line}`, color: T.text, width: 150 }} className="px-1.5 py-1 rounded" />
                </label>
              )}
            </div>
          )}
          <div style={{ borderTop: `1px solid ${T.line}` }} className="p-3 flex items-center gap-2">
            <button onClick={copyJSON} style={{ background: T.chrome2, border: `1px solid ${T.line}`, color: T.text }} className="flex-1 px-2 py-1.5 rounded text-xs font-mono flex items-center justify-center gap-1"><Copy size={13} /> Copy</button>
            <button onClick={downloadJSON} style={{ background: T.accent, color: "#fff" }} className="flex-1 px-2 py-1.5 rounded text-xs font-mono flex items-center justify-center gap-1"><Download size={13} /> Layout JSON</button>
            <button onClick={() => { setLayers(makeStarter()); setSelectedId("L1"); setLog([]); }} title="Reset to starter"
              style={{ background: T.chrome2, border: `1px solid ${T.line}`, color: T.muted }} className="px-2 py-1.5 rounded text-xs font-mono"><RotateCcw size={13} /></button>
          </div>
        </div>
      </div>
    </div>
  );
}
